import pandas as pd
import re
business_data = locals()['var_function-call-9640767253786095022']
df_business = pd.DataFrame(business_data)

def extract_state_new(description):
    if description:
        match = re.search(r', ([A-Z]{2}),', description)
        if match:
            return match.group(1)
    return None

df_business['state'] = df_business['description'].apply(extract_state_new)
df_business_filtered = df_business.dropna(subset=['state'])
df_business_filtered['review_count'] = pd.to_numeric(df_business_filtered['review_count'])

state_review_counts = df_business_filtered.groupby('state')['review_count'].sum().reset_index()

if not state_review_counts.empty:
    highest_review_state = state_review_counts.loc[state_review_counts['review_count'].idxmax()]
    result = highest_review_state.to_json()
else:
    result = {'error': 'No states found or review counts are empty'}

print('__RESULT__:')
print(result)

